focus_visible.css:
/* Focus visible — WCAG AA */
*:focus { outline: none; }
*:focus-visible { outline: 2px solid var(--primary); outline-offset: 2px; border-radius: calc(var(--radius) + 2px); }

/* Skip-to-main focus */
.skip-link:focus { position: fixed; top: 16px; left: 16px; z-index: 9999; background: var(--primary); color: var(--bg); padding: 8px 16px; border-radius: var(--radius); font-weight: 700; }

toast_notification.js:
function showToast(message, type = 'success') {
  const t = document.createElement('div');
  t.className = 'toast toast-' + type;
  t.setAttribute('role', 'alert');
  t.setAttribute('aria-live', 'polite');
  t.textContent = message;
  document.body.appendChild(t);
  requestAnimationFrame(() => t.classList.add('show'));
  setTimeout(() => { t.classList.remove('show'); setTimeout(() => t.remove(), 300); }, 3000);
}
